INSERT INTO qualification_requirements (qualification_code, unit_code, unit_title, lo_number, lo_text, ac_code, ac_text) VALUES
('601/7345/2','NETK3-01','Understand Health, Safety and Environmental Considerations',1,'Understand how relevant legislation applies in the workplace.','1.1','Identify roles and responsibilities with regard to current relevant Health and Safety legislation.'),
('601/7345/2','NETK3-01','Understand Health, Safety and Environmental Considerations',1,'Understand how relevant legislation applies in the workplace.','1.2','Identify roles and responsibilities with regard to current relevant environmental legislation.'),
('601/7345/2','NETK3-01','Understand Health, Safety and Environmental Considerations',2,'Understand the procedures for dealing with Environmental and Health and Safety situations in the work environment.','2.1','State the procedures that should be followed in the case of accidents which involve injury, including requirements for the treatment of electric shock/electrical burns.'),
('601/7345/2','NETK3-01','Understand Health, Safety and Environmental Considerations',2,'Understand the procedures for dealing with Environmental and Health and Safety situations in the work environment.','2.2','Specify appropriate procedures which should be followed when emergency situations occur in the workplace.'),
('601/7345/2','NETK3-01','Understand Health, Safety and Environmental Considerations',2,'Understand the procedures for dealing with Environmental and Health and Safety situations in the work environment.','2.3','State the actions to be taken in situations which exceed their level of responsibility for Health and Safety in the workplace.'),
('601/7345/2','NETK3-01','Understand Health, Safety and Environmental Considerations',2,'Understand the procedures for dealing with Environmental and Health and Safety situations in the work environment.','2.4','Specify appropriate responsible persons to whom health and safety and welfare related matters should be reported.'),
('601/7345/2','NETK3-01','Understand Health, Safety and Environmental Considerations',2,'Understand the procedures for dealing with Environmental and Health and Safety situations in the work environment.','2.5','Describe the ways in which the environment may be affected by work activities.'),
('601/7345/2','NETK3-01','Understand Health, Safety and Environmental Considerations',2,'Understand the procedures for dealing with Environmental and Health and Safety situations in the work environment.','2.6','Specify the current requirements and good working practices for processing waste on site.'),
('601/7345/2','NETK3-01','Understand Health, Safety and Environmental Considerations',2,'Understand the procedures for dealing with Environmental and Health and Safety situations in the work environment.','2.7','Explain why it is important to report any hazards to the environment that arise from work procedures.'),
('601/7345/2','NETK3-01','Understand Health, Safety and Environmental Considerations',3,'Be able to demonstrate and understand the procedures for establishing a safe working environment.','3.1','State the procedure for producing risk assessments and method statements in accordance with their level of responsibility.'),
('601/7345/2','NETK3-01','Understand Health, Safety and Environmental Considerations',3,'Be able to demonstrate and understand the procedures for establishing a safe working environment.','3.2','Describe the procedures that should be taken to remove or minimise risks before deciding PPE is needed.'),
('601/7345/2','NETK3-01','Understand Health, Safety and Environmental Considerations',3,'Be able to demonstrate and understand the procedures for establishing a safe working environment.','3.3','State the purpose of PPE.'),
('601/7345/2','NETK3-01','Understand Health, Safety and Environmental Considerations',3,'Be able to demonstrate and understand the procedures for establishing a safe working environment.','3.4','Specify the appropriate protective clothing and equipment that is required for identified work tasks.'),
('601/7345/2','NETK3-01','Understand Health, Safety and Environmental Considerations',3,'Be able to demonstrate and understand the procedures for establishing a safe working environment.','3.5','State the first aid facilities that must be available in the work area in accordance with health and safety regulations.'),
('601/7345/2','NETK3-01','Understand Health, Safety and Environmental Considerations',3,'Be able to demonstrate and understand the procedures for establishing a safe working environment.','3.6','Explain why it is important not to misuse first aid equipment/supplies and to replace first aid supplies once used.'),
('601/7345/2','NETK3-01','Understand Health, Safety and Environmental Considerations',3,'Be able to demonstrate and understand the procedures for establishing a safe working environment.','3.7','Describe and demonstrate safe practices and procedures for the use of equipment and materials in the working environment.'),
('601/7345/2','NETK3-01','Understand Health, Safety and Environmental Considerations',3,'Be able to demonstrate and understand the procedures for establishing a safe working environment.','3.8','Specify and demonstrate the procedures for ensuring electrical systems are safe to work on.'),
('601/7345/2','NETK3-01','Understand Health, Safety and Environmental Considerations',3,'Be able to demonstrate and understand the procedures for establishing a safe working environment.','3.9','State the implications of: a) Carrying out safe isolation procedures; b) Not carrying out safe isolation procedures.'),
('601/7345/2','NETK3-01','Understand Health, Safety and Environmental Considerations',4,'Understand the requirements for identifying and dealing with hazards in the work environment.','4.1','Identify hazard symbols on packaging and labeling of substances and mixtures.'),
('601/7345/2','NETK3-01','Understand Health, Safety and Environmental Considerations',4,'Understand the requirements for identifying and dealing with hazards in the work environment.','4.2','Define what is meant by the term hazard in relation to health and safety legislation in the workplace.'),
('601/7345/2','NETK3-01','Understand Health, Safety and Environmental Considerations',4,'Understand the requirements for identifying and dealing with hazards in the work environment.','4.3','Identify specific hazards associated with the installation and maintenance of electrical systems and equipment.'),
('601/7345/2','NETK3-01','Understand Health, Safety and Environmental Considerations',4,'Understand the requirements for identifying and dealing with hazards in the work environment.','4.4','Describe situations which can constitute a hazard in the workplace.'),
('601/7345/2','NETK3-01','Understand Health, Safety and Environmental Considerations',4,'Understand the requirements for identifying and dealing with hazards in the work environment.','4.5','Explain practices and procedures for addressing hazards in the work place.'),
('601/7345/2','NETK3-01','Understand Health, Safety and Environmental Considerations',4,'Understand the requirements for identifying and dealing with hazards in the work environment.','4.6','Identify the correct type of fire extinguisher for a particular type of fire.'),
('601/7345/2','NETK3-01','Understand Health, Safety and Environmental Considerations',4,'Understand the requirements for identifying and dealing with hazards in the work environment.','4.7','Explain situations where asbestos may be encountered.'),
('601/7345/2','NETK3-01','Understand Health, Safety and Environmental Considerations',4,'Understand the requirements for identifying and dealing with hazards in the work environment.','4.8','Specify the procedures for dealing with the suspected presence of asbestos in the workplace.');
INSERT INTO qualification_requirements (qualification_code, unit_code, unit_title, lo_number, lo_text, ac_code, ac_text) VALUES
('601/7345/2','NETK3-03','Understand How to Plan and Oversee Electrical Work Activities',1,'Understand the requirements for liaising with others when organising and overseeing work activities.','1.1','Describe techniques for the communication with others for the purpose of: motivation; instruction; monitoring; co-operation and teamwork.'),
('601/7345/2','NETK3-03','Understand How to Plan and Oversee Electrical Work Activities',1,'Understand the requirements for liaising with others when organising and overseeing work activities.','1.2','Describe methods of determining the competence of operatives for whom they are responsible.'),
('601/7345/2','NETK3-03','Understand How to Plan and Oversee Electrical Work Activities',1,'Understand the requirements for liaising with others when organising and overseeing work activities.','1.3','Specify procedures for re-scheduling work to co-ordinate with changing conditions in the workplace and to coincide with other trades.'),
('601/7345/2','NETK3-03','Understand How to Plan and Oversee Electrical Work Activities',1,'Understand the requirements for liaising with others when organising and overseeing work activities.','1.4','Specify organisational procedures for completing the documentation that is required during work operations.'),
('601/7345/2','NETK3-03','Understand How to Plan and Oversee Electrical Work Activities',2,'Understand the requirements for organising and overseeing work programmes.','2.1','Describe how to plan and implement: work allocations; duties of operatives for whom they are responsible; coordination with other services and personnel.'),
('601/7345/2','NETK3-03','Understand How to Plan and Oversee Electrical Work Activities',2,'Understand the requirements for organising and overseeing work programmes.','2.2','State the procedures for carrying out work activities that will: maintain the safety of the work environment; maintain cost effectiveness; ensure compliance with the programme of work.'),
('601/7345/2','NETK3-03','Understand How to Plan and Oversee Electrical Work Activities',2,'Understand the requirements for organising and overseeing work programmes.','2.3','Identify the industry standards that are relevant to activities carried out during the installation of electrical systems and equipment, including the current editions.'),
('601/7345/2','NETK3-03','Understand How to Plan and Oversee Electrical Work Activities',2,'Understand the requirements for organising and overseeing work programmes.','2.4','Evaluate within the scope of the work programme and operations the responsibilities of themselves and others.'),
('601/7345/2','NETK3-03','Understand How to Plan and Oversee Electrical Work Activities',2,'Understand the requirements for organising and overseeing work programmes.','2.5','Identify the procedures for dealing with changes to an original contract specification.'),
('601/7345/2','NETK3-03','Understand How to Plan and Oversee Electrical Work Activities',2,'Understand the requirements for organising and overseeing work programmes.','2.6','Identify installations that require specialist advice or guidance: Hazardous installations; Installations outside the scope of BS 7671.'),
('601/7345/2','NETK3-03','Understand How to Plan and Oversee Electrical Work Activities',2,'Understand the requirements for organising and overseeing work programmes.','2.7','Explain how the work completion time is estimated taking into account influential factors.'),
('601/7345/2','NETK3-03','Understand How to Plan and Oversee Electrical Work Activities',2,'Understand the requirements for organising and overseeing work programmes.','2.8','State the possible consequences of not: completing work within the estimated time; meeting the requirements of the programme of work; using the specified materials; installing materials and equipment as specified.'),
('601/7345/2','NETK3-03','Understand How to Plan and Oversee Electrical Work Activities',2,'Understand the requirements for organising and overseeing work programmes.','2.9','Specify and evaluate methods of producing and illustrating work programmes.'),
('601/7345/2','NETK3-03','Understand How to Plan and Oversee Electrical Work Activities',3,'Understand the requirements for organising the provision and storage of resources that are required for work activities.','3.1','Interpret the installation specification and work programme to identify resource requirements.'),
('601/7345/2','NETK3-03','Understand How to Plan and Oversee Electrical Work Activities',3,'Understand the requirements for organising the provision and storage of resources that are required for work activities.','3.2','Interpret the material schedule to confirm that materials available are: the right type; fit for purpose; in the correct quantity; suitable for work to be completed cost efficiently.'),
('601/7345/2','NETK3-03','Understand How to Plan and Oversee Electrical Work Activities',3,'Understand the requirements for organising the provision and storage of resources that are required for work activities.','3.3','Specify the storage and transportation requirements for all materials required in the work location.'),
('601/7345/2','NETK3-03','Understand How to Plan and Oversee Electrical Work Activities',3,'Understand the requirements for organising the provision and storage of resources that are required for work activities.','3.4','Specify procedures to ensure the safe and effective storage of materials, tools and equipment in the work location.');
INSERT INTO qualification_requirements (qualification_code, unit_code, unit_title, lo_number, lo_text, ac_code, ac_text) VALUES
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',1,'Understand how to prepare for the installation of wiring systems.','1.1','Identify relevant sources of information which will inform electrical work.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',1,'Understand how to prepare for the installation of wiring systems.','1.2','Describe the actions required to ensure that electrical work sites are correctly prepared in terms of health and safety considerations.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',1,'Understand how to prepare for the installation of wiring systems.','1.3','State why it is important to check for any pre-existing damage to customer/client property prior to commencement of any work activity.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',1,'Understand how to prepare for the installation of wiring systems.','1.4','Explain how to check for any pre-existing damage to customer/client property: a) Equipment and components; b) Building decor and floor finishes.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',1,'Understand how to prepare for the installation of wiring systems.','1.5','State the actions that should be taken if pre-existing damage to customer/client property is identified.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',1,'Understand how to prepare for the installation of wiring systems.','1.6','Specify methods for protecting the fabric and structure of the property before and during electrical work.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',2,'Understand the applications of wiring systems.','2.1','Explain the constructional features, applications, advantages and limitations of electrical cables.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',2,'Understand the applications of wiring systems.','2.2','Explain the characteristics of containment, support and wiring systems used in electrical installations.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',2,'Understand the applications of wiring systems.','2.3','Determine the size of conduit and trunking as appropriate to the size and number of cables.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',2,'Understand the applications of wiring systems.','2.4','Describe the factors which affect the selection of wiring systems, associated equipment and enclosures.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',2,'Understand the applications of wiring systems.','2.5','Assess and select suitable wiring systems and equipment appropriate to the situation and use.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',3,'Understand the practices and procedures for carrying out electrical work.','3.1','State the procedures for selecting and safely using appropriate hand tools, power tools and adhesives for electrical work.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',3,'Understand the practices and procedures for carrying out electrical work.','3.2','State the procedures for selecting and safely using equipment for measuring and marking out for wiring systems, equipment and enclosures.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',3,'Understand the practices and procedures for carrying out electrical work.','3.3','State the criteria for selecting and safely using tools and equipment for fixing and installing wiring systems, associated equipment and enclosures.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',3,'Understand the practices and procedures for carrying out electrical work.','3.4','State the criteria for selecting and safely using fixing devices for wiring systems, associated equipment and enclosures.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',3,'Understand the practices and procedures for carrying out electrical work.','3.5','Assess and specify the installation methods and procedures to ensure that in accordance with the installation specification and statutory and non-statutory regulations: a) wiring systems, enclosures, cables and components are securely fixed and installed; b) a wiring system''s mechanical integrity is maintained; c) no damage to the wiring system or its components has occurred.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',3,'Understand the practices and procedures for carrying out electrical work.','3.6','Specify methods and techniques for restoring the building fabric.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',4,'Understand the characteristics and applications of supply systems and consumer''s equipment.','4.1','Explain the characteristics and applications of earthing arrangements.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',4,'Understand the characteristics and applications of supply systems and consumer''s equipment.','4.2','Explain the characteristics and applications of supply systems.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',4,'Understand the characteristics and applications of supply systems and consumer''s equipment.','4.3','Specify the arrangements for electrical installations and systems with regard to provision for: a) Isolation and switching (including DC isolators); b) Overcurrent protection.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',5,'Understand earthing and protection.','5.1','Explain the purpose of earthing and protective conductors.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',5,'Understand earthing and protection.','5.2','Identify extraneous and exposed conductive parts.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',5,'Understand earthing and protection.','5.3','Describe the requirements and measures for protection against electric shock.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',5,'Understand earthing and protection.','5.4','State the maximum disconnection time for different types of circuit.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',5,'Understand earthing and protection.','5.5','Explain the earth fault loop path and earth fault loop impedance.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',5,'Understand earthing and protection.','5.6','Specify requirements and applications of functional earthing.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',5,'Understand earthing and protection.','5.7','Select suitably sized protective conductors in accordance with BS 7671.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',6,'Understand protection against fault current.','6.1','Identify types of and reasons for overcurrent.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',6,'Understand protection against fault current.','6.2','Explain the operating principles, applications and limitations of protective devices.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',6,'Understand protection against fault current.','6.3','Identify fault current capacities of devices.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',6,'Understand protection against fault current.','6.4','Outline the need for selectivity between protective devices.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',7,'Understand electrical systems and circuits.','7.1','Describe the characteristics of standard electrical circuits.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',7,'Understand electrical systems and circuits.','7.2','Outline the key characteristics of particular electrical systems and circuits and the applications of these circuits and systems.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',8,'Understand the electrical design procedure.','8.1','State the purpose of diversity factors.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',8,'Understand the electrical design procedure.','8.2','Select suitable current using equipment giving consideration to energy efficiency and relevant codes of practice for sustainability.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',8,'Understand the electrical design procedure.','8.3','Determine the maximum demand (of an installation) after the application of diversity.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',8,'Understand the electrical design procedure.','8.4','Determine the design current.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',8,'Understand the electrical design procedure.','8.5','Select a suitably rated protective device.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',8,'Understand the electrical design procedure.','8.6','Establish the installation method reference.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',8,'Understand the electrical design procedure.','8.7','Determine appropriate rating factors.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',8,'Understand the electrical design procedure.','8.8','Determine the minimum cross-sectional area of live conductors taking into consideration current carrying capacity and voltage drop.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',8,'Understand the electrical design procedure.','8.9','Establish if the voltage drop is acceptable.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',8,'Understand the electrical design procedure.','8.10','Verify if the disconnection times have been achieved.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',8,'Understand the electrical design procedure.','8.11','Evaluate thermal constraints.'),
('601/7345/2','NETK3-04','Understand Design and Installation Practices and Procedures',8,'Understand the electrical design procedure.','8.12','Interpret the requirements of sources of information in the design of an installation.');
INSERT INTO qualification_requirements (qualification_code, unit_code, unit_title, lo_number, lo_text, ac_code, ac_text) VALUES
('601/7345/2','NETK3-05','Understand Terminations and Connections of Conductors',1,'Understand the regulatory requirements and procedures for terminating and connecting conductors and cables in electrical wiring systems and equipment.','1.1','Identify and interpret appropriate sources of relevant information for the termination and connection of conductors and cables in electrical wiring systems and equipment.'),
('601/7345/2','NETK3-05','Understand Terminations and Connections of Conductors',1,'Understand the regulatory requirements and procedures for terminating and connecting conductors and cables in electrical wiring systems and equipment.','1.2','Describe methods and procedures appropriate to the installation environment to ensure the safe and effective termination and connection of conductors and cables in electrical wiring systems and equipment.'),
('601/7345/2','NETK3-05','Understand Terminations and Connections of Conductors',2,'Understand the procedures and applications of different methods of terminating, connecting and supporting conductors and cables in electrical wiring systems and equipment.','2.1','Explain the advantages, limitations and applications of the following connection methods: screw; crimped; soldered; non-screw compression; insulation displacement; compact lever; DC rated terminal.'),
('601/7345/2','NETK3-05','Understand Terminations and Connections of Conductors',2,'Understand the procedures and applications of different methods of terminating, connecting and supporting conductors and cables in electrical wiring systems and equipment.','2.2','Describe the procedures for verifying that terminations and connections are electrically and mechanically sound.'),
('601/7345/2','NETK3-05','Understand Terminations and Connections of Conductors',2,'Understand the procedures and applications of different methods of terminating, connecting and supporting conductors and cables in electrical wiring systems and equipment.','2.3','Explain the consequences of terminations not being electrically and mechanically sound in terms of: high resistance joints; corrosion and erosion.'),
('601/7345/2','NETK3-05','Understand Terminations and Connections of Conductors',2,'Understand the procedures and applications of different methods of terminating, connecting and supporting conductors and cables in electrical wiring systems and equipment.','2.4','Interpret and apply the techniques and methods for the safe and effective termination and connection of: flexible cables; single and multicore thermoplastic (PVC) and thermosetting insulated cables; PVC/PVC flat profile cable; MICC; SWA cables; Galvanised steel wire braid; data cables; fire performance cable; DC cables.'),
('601/7345/2','NETK3-05','Understand Terminations and Connections of Conductors',2,'Understand the procedures and applications of different methods of terminating, connecting and supporting conductors and cables in electrical wiring systems and equipment.','2.5','Apply techniques and methods for effective support of cables.');
INSERT INTO qualification_requirements (qualification_code, unit_code, unit_title, lo_number, lo_text, ac_code, ac_text) VALUES
('601/7345/2','NETK3-06A','Inspection, Testing and Commissioning',1,'Understand the requirements for completing the safe isolation of electrical circuits and installations.','1.1','State the requirements of the Electricity at Work Regulations for the safe inspection of electrical systems and equipment.'),
('601/7345/2','NETK3-06A','Inspection, Testing and Commissioning',1,'Understand the requirements for completing the safe isolation of electrical circuits and installations.','1.2','Specify the appropriate procedure for completing safe isolation.'),
('601/7345/2','NETK3-06A','Inspection, Testing and Commissioning',1,'Understand the requirements for completing the safe isolation of electrical circuits and installations.','1.3','State the implications of carrying out safe isolation.'),
('601/7345/2','NETK3-06A','Inspection, Testing and Commissioning',1,'Understand the requirements for completing the safe isolation of electrical circuits and installations.','1.4','State the implications of not carrying out safe isolation.'),
('601/7345/2','NETK3-06A','Inspection, Testing and Commissioning',1,'Understand the requirements for completing the safe isolation of electrical circuits and installations.','1.5','Identify the Health and Safety requirements which apply when inspecting, testing and commissioning electrical installations and circuits.'),
('601/7345/2','NETK3-06A','Inspection, Testing and Commissioning',1,'Understand the requirements for completing the safe isolation of electrical circuits and installations.','1.6','Identify the procedure for detecting potential diverted neutral currents.'),
('601/7345/2','NETK3-06A','Inspection, Testing and Commissioning',2,'Understand the requirement for inspection of electrical installations.','2.1','State the purpose of the inspection of electrical installations.'),
('601/7345/2','NETK3-06A','Inspection, Testing and Commissioning',2,'Understand the requirement for inspection of electrical installations.','2.2','State the requirements of the inspection.'),
('601/7345/2','NETK3-06A','Inspection, Testing and Commissioning',2,'Understand the requirement for inspection of electrical installations.','2.3','Identify the relevant documents associated with the inspection, testing, commissioning and reporting of an electrical installation.'),
('601/7345/2','NETK3-06A','Inspection, Testing and Commissioning',2,'Understand the requirement for inspection of electrical installations.','2.4','Specify the information that is required by the inspector to conduct the inspection of an electrical installation.'),
('601/7345/2','NETK3-06A','Inspection, Testing and Commissioning',3,'Understand the requirements for completing the inspection of electrical installations prior to their being placed into service.','3.1','Select appropriate items to be checked during the inspection process.'),
('601/7345/2','NETK3-06A','Inspection, Testing and Commissioning',3,'Understand the requirements for completing the inspection of electrical installations prior to their being placed into service.','3.2','Identify human senses appropriate for initial verification.'),
('601/7345/2','NETK3-06A','Inspection, Testing and Commissioning',3,'Understand the requirements for completing the inspection of electrical installations prior to their being placed into service.','3.3','State how the senses can be used during the inspection process.'),
('601/7345/2','NETK3-06A','Inspection, Testing and Commissioning',3,'Understand the requirements for completing the inspection of electrical installations prior to their being placed into service.','3.4','Specify the requirements for the inspection of electrical installations.'),
('601/7345/2','NETK3-06A','Inspection, Testing and Commissioning',3,'Understand the requirements for completing the inspection of electrical installations prior to their being placed into service.','3.5','Specify the requirements for the inspection to include: a) Special installations and locations, as identified in Part 7 of BS 7671; b) IP Classification of equipment.'),
('601/7345/2','NETK3-06A','Inspection, Testing and Commissioning',4,'Understand the requirements for the safe testing and commissioning of electrical installations.','4.1','State the tests to be carried out on an electrical installation in accordance with BS 7671 and IET Guidance Note 3.'),
('601/7345/2','NETK3-06A','Inspection, Testing and Commissioning',4,'Understand the requirements for the safe testing and commissioning of electrical installations.','4.2','Identify the appropriate instrument for each test to be carried out in terms of: a) The instrument is fit for purpose; b) Identifying the correct scale or setting.'),
('601/7345/2','NETK3-06A','Inspection, Testing and Commissioning',4,'Understand the requirements for the safe testing and commissioning of electrical installations.','4.3','Specify the requirements for the safe use of instruments to be used for testing and commissioning, to include: a) Checks required to prove that test instruments are safe and functioning correctly; b) The requirements for test leads and probes must comply with HSE Guidance GS38; c) The need for instruments to be regularly checked and calibrated.'),
('601/7345/2','NETK3-06A','Inspection, Testing and Commissioning',4,'Understand the requirements for the safe testing and commissioning of electrical installations.','4.4','Explain why it is necessary for test results to comply with standard values.'),
('601/7345/2','NETK3-06A','Inspection, Testing and Commissioning',4,'Understand the requirements for the safe testing and commissioning of electrical installations.','4.5','State the actions to be taken in the event of unsatisfactory results being obtained.'),
('601/7345/2','NETK3-06A','Inspection, Testing and Commissioning',4,'Understand the requirements for the safe testing and commissioning of electrical installations.','4.6','Explain why testing is carried out in the sequence specified in BS 7671 and IET Guidance Note 3.'),
('601/7345/2','NETK3-06A','Inspection, Testing and Commissioning',5,'Understand the requirements for testing before circuits are energised.','5.1','State why it is necessary to verify continuity to include: a) Protective bonding conductors; b) Circuit protective conductors; c) Ring final circuit conductors.'),
('601/7345/2','NETK3-06A','Inspection, Testing and Commissioning',5,'Understand the requirements for testing before circuits are energised.','5.2','State the methods for verifying continuity to include: a) Protective conductors; b) Ring final circuit conductors.'),
('601/7345/2','NETK3-06A','Inspection, Testing and Commissioning',5,'Understand the requirements for testing before circuits are energised.','5.3','Explain factors that affect conductor resistance values.'),
