INSERT INTO qualification_requirements (qualification_code, unit_code, unit_title, lo_number, lo_text, ac_code, ac_text) VALUES
('601/7345/2','NETP3-01','Apply Health, Safety and Environmental Considerations',1,'Be able to apply relevant health and safety legislation in the workplace','1.1','Identify which workplace health and safety procedures are relevant to the working environment and comply with their duties and obligations as defined by current legislation and organisational procedures'),
('601/7345/2','NETP3-01','Apply Health, Safety and Environmental Considerations',1,'Be able to apply relevant health and safety legislation in the workplace','1.2','Produce a risk assessment and method statement in accordance with organisational procedures for a given work activity'),
('601/7345/2','NETP3-01','Apply Health, Safety and Environmental Considerations',1,'Be able to apply relevant health and safety legislation in the workplace','1.3','Work within the requirements of: a) Risk assessments; b) Method statements; c) Safe systems of work'),
('601/7345/2','NETP3-01','Apply Health, Safety and Environmental Considerations',2,'Be able to assess the work environment for hazards and identify remedial actions in accordance with health and safety legislation','2.1','Identify unsafe situations and conditions and take remedial actions'),
('601/7345/2','NETP3-01','Apply Health, Safety and Environmental Considerations',2,'Be able to assess the work environment for hazards and identify remedial actions in accordance with health and safety legislation','2.2','Assess the work environment and revise work practices accordingly to take into account hazards which could cause harm, including the handling of potentially hazardous: a) Materials; b) Tools; c) Equipment'),
('601/7345/2','NETP3-01','Apply Health, Safety and Environmental Considerations',2,'Be able to assess the work environment for hazards and identify remedial actions in accordance with health and safety legislation','2.3','Identify any hazards which may present a high risk and report their presence to the relevant persons who have overall responsibility for health and safety in the workplace'),
('601/7345/2','NETP3-01','Apply Health, Safety and Environmental Considerations',2,'Be able to assess the work environment for hazards and identify remedial actions in accordance with health and safety legislation','2.4','Apply measures to control health and safety hazards'),
('601/7345/2','NETP3-01','Apply Health, Safety and Environmental Considerations',2,'Be able to assess the work environment for hazards and identify remedial actions in accordance with health and safety legislation','2.5','Select and use correct personal protective equipment'),
('601/7345/2','NETP3-01','Apply Health, Safety and Environmental Considerations',3,'Be able to apply methods and procedures to ensure work on site is in accordance with health and safety legislation','3.1','Demonstrate a level of personal conduct and behaviour within the workplace, to ensure that the health and safety of themselves and others is not endangered'),
('601/7345/2','NETP3-01','Apply Health, Safety and Environmental Considerations',3,'Be able to apply methods and procedures to ensure work on site is in accordance with health and safety legislation','3.2','Apply procedures to ensure the safe use, maintenance and storage of tools, plant and equipment as stipulated in: a) Workplace policies (company and site); b) Supplier information; c) Manufacturer''s instructions'),
('601/7345/2','NETP3-01','Apply Health, Safety and Environmental Considerations',3,'Be able to apply methods and procedures to ensure work on site is in accordance with health and safety legislation','3.3','Comply with information, warning, mandatory instruction, and prohibition notices'),
('601/7345/2','NETP3-01','Apply Health, Safety and Environmental Considerations',3,'Be able to apply methods and procedures to ensure work on site is in accordance with health and safety legislation','3.4','Apply procedures to ensure the safety of the work location through the correct use of guards, barriers and notices'),
('601/7345/2','NETP3-01','Apply Health, Safety and Environmental Considerations',3,'Be able to apply methods and procedures to ensure work on site is in accordance with health and safety legislation','3.5','Use access equipment correctly: a) Ladder; b) Tower scaffold or MEWP; c) Stepladder; d) Platform'),
('601/7345/2','NETP3-01','Apply Health, Safety and Environmental Considerations',4,'Be able to work in accordance with environmental legislation for electrical services','4.1','Demonstrate appropriate procedures for the safe handling, storage and disposal of hazardous materials and products: a) Environmental Protection Act; b) Hazardous Waste Regulations; c) Pollution Prevention and Control Act; d) Control of Pollution Act; e) Control of Noise at Work Regulations; f) Environment Act');
INSERT INTO qualification_requirements (qualification_code, unit_code, unit_title, lo_number, lo_text, ac_code, ac_text) VALUES
('601/7345/2','NETP3-03','Organise and Oversee the Electrical Work Environment',1,'Be able to provide relevant people with technical and functional information for work on electrical systems and equipment','1.1','Liaise with relevant people to evaluate the information they require to ensure that systems, equipment or components can be operated safely and effectively'),
('601/7345/2','NETP3-03','Organise and Oversee the Electrical Work Environment',1,'Be able to provide relevant people with technical and functional information for work on electrical systems and equipment','1.2','Identify appropriate technical and functional information that is required for the work activity'),
('601/7345/2','NETP3-03','Organise and Oversee the Electrical Work Environment',1,'Be able to provide relevant people with technical and functional information for work on electrical systems and equipment','1.3','Provide information in a timely, courteous, suitable and professional manner in accordance with organisational procedures and engineering standards'),
('601/7345/2','NETP3-03','Organise and Oversee the Electrical Work Environment',2,'Be able to oversee Health and Safety during work on electrical systems and equipment','2.1','Produce, or revise generic, risk assessments and method statements, to cover their own work and others working the area (colleagues and other operatives) in accordance with their level of responsibility'),
('601/7345/2','NETP3-03','Organise and Oversee the Electrical Work Environment',2,'Be able to oversee Health and Safety during work on electrical systems and equipment','2.2','Implement suitable procedures to confirm that work is being completed in accordance with health and safety legislation and industry standards'),
('601/7345/2','NETP3-03','Organise and Oversee the Electrical Work Environment',3,'Be able to coordinate liaison with other relevant persons during work activities','3.1','Select effective procedures to ensure coordination with other workers/contractors, including steps to resolve issues which are outside the scope of their job role'),
('601/7345/2','NETP3-03','Organise and Oversee the Electrical Work Environment',3,'Be able to coordinate liaison with other relevant persons during work activities','3.2','Evaluate and apply communication techniques that are clear, accurate and appropriate to the situation'),
('601/7345/2','NETP3-03','Organise and Oversee the Electrical Work Environment',3,'Be able to coordinate liaison with other relevant persons during work activities','3.3','Demonstrate working effectively with colleagues to enhance performance'),
('601/7345/2','NETP3-03','Organise and Oversee the Electrical Work Environment',4,'Be able to organise and oversee work activities and operations','4.1','Organise operatives by allocating duties and responsibilities to make the best use of their competence and skill'),
('601/7345/2','NETP3-03','Organise and Oversee the Electrical Work Environment',4,'Be able to organise and oversee work activities and operations','4.2','Monitor the work of operatives to ensure it is in accordance with: a. Industry working practices; b. The programme of work; c. Health and Safety requirements; d. Cost effectiveness; e. Environmental considerations'),
('601/7345/2','NETP3-03','Organise and Oversee the Electrical Work Environment',4,'Be able to organise and oversee work activities and operations','4.3','Evaluate and apply appropriate procedures to correct issues that arise during work activities'),
('601/7345/2','NETP3-03','Organise and Oversee the Electrical Work Environment',5,'Be able to organise a programme for working on electrical systems and equipment','5.1','Produce a simple programme of work from the work specification, including requirements for the following: a. An estimation of the amount of time required for completion of the work; b. Where liaison with other trades may be necessary'),
('601/7345/2','NETP3-03','Organise and Oversee the Electrical Work Environment',5,'Be able to organise a programme for working on electrical systems and equipment','5.2','Communicate with others clearly and concisely'),
('601/7345/2','NETP3-03','Organise and Oversee the Electrical Work Environment',5,'Be able to organise a programme for working on electrical systems and equipment','5.3','Assess situations when it is necessary to liaise with other relevant parties to resolve issues'),
('601/7345/2','NETP3-03','Organise and Oversee the Electrical Work Environment',6,'Be able to organise the resource requirements for work on electrical systems and equipment','6.1','Organise the provision of resources (such as materials, fixings, plant, labour or tools)'),
('601/7345/2','NETP3-03','Organise and Oversee the Electrical Work Environment',6,'Be able to organise the resource requirements for work on electrical systems and equipment','6.2','Confirm that the materials available are: a. The right type; b. Fit for purpose; c. In the correct quantity; d. Suitable for work to be completed cost-efficiently'),
('601/7345/2','NETP3-03','Organise and Oversee the Electrical Work Environment',6,'Be able to organise the resource requirements for work on electrical systems and equipment','6.3','Ensure that resources are undamaged at the point of delivery'),
('601/7345/2','NETP3-03','Organise and Oversee the Electrical Work Environment',6,'Be able to organise the resource requirements for work on electrical systems and equipment','6.4','Demonstrate effective measures which ensure the safe and effective storage of materials, tools and equipment in the work location');
INSERT INTO qualification_requirements (qualification_code, unit_code, unit_title, lo_number, lo_text, ac_code, ac_text) VALUES
('601/7345/2','NETP3-04A','Apply Design and Installation Practices and Procedures',1,'Prepare to install wiring systems, enclosures and associated equipment','1.1','Assess and apply appropriate procedures to include: a) Adopting appropriate PPE; b) Following a safe system of work (e.g. working in accordance with a risk assessment and method statement); c) Selecting appropriate tools/equipment for the installation work'),
('601/7345/2','NETP3-04A','Apply Design and Installation Practices and Procedures',1,'Prepare to install wiring systems, enclosures and associated equipment','1.2','Prepare to install wiring systems, enclosures and associated equipment, to include: a) Confirm secure site storage facilities for tools, equipment, materials and components; b) Select materials (equipment and components) in accordance with the installation specification; c) Report any pre-work damage/defects to existing equipment or building features, to the relevant person (Such as: customer/client, site/line manager); d) Confirm site readiness for installation work to begin; e) Confirm authorisation for the installation work to start'),
('601/7345/2','NETP3-04A','Apply Design and Installation Practices and Procedures',1,'Prepare to install wiring systems, enclosures and associated equipment','1.3','Use documentation to confirm that materials and equipment is of the correct quantity and is free from damage'),
('601/7345/2','NETP3-04A','Apply Design and Installation Practices and Procedures',1,'Prepare to install wiring systems, enclosures and associated equipment','1.4','Ensure the planned locations for the wiring system and associated equipment are compatible with other building services (e.g. gas, water or other electrical services)'),
('601/7345/2','NETP3-04A','Apply Design and Installation Practices and Procedures',1,'Prepare to install wiring systems, enclosures and associated equipment','1.5','Check the planned locations for the wiring system in terms of: a) Cosmetic appearance; b) External influences'),
('601/7345/2','NETP3-04A','Apply Design and Installation Practices and Procedures',2,'Interpret appropriate information for the installation of wiring systems, enclosures and associated equipment','2.1','Use sources of information to enable the installation of wiring systems, enclosures and associated equipment to be carried out including: a) Specifications; b) Work schedules/programmes; c) Manufacturer instructions; d) Layout Drawings; e) Other appropriate source of information (e.g. BS 7671, other plans or diagrams, ''approved documents'', building regulations)'),
('601/7345/2','NETP3-04A','Apply Design and Installation Practices and Procedures',3,'Install wiring systems and equipment in accordance with current relevant statutory and non-statutory regulations','3.1','Use appropriate measuring and marking out techniques which are appropriate to the wiring system, wiring enclosure and/or associated equipment that is being installed'),
('601/7345/2','NETP3-04A','Apply Design and Installation Practices and Procedures',3,'Install wiring systems and equipment in accordance with current relevant statutory and non-statutory regulations','3.2','Install cables in accordance with BS 7671, the installation specification and programme of work: Cover Five a) Single-core cable (singles); b) Multicore insulated cable; c) PVC/PVC flat profile cable (twin and earth); d) MICC cable; e) Fire performance (such as FP200 etc.); f) SWA cable; g) GSWB galvanised steel wire braid (SY); h) Data/PoE; i) DC cabling'),
('601/7345/2','NETP3-04A','Apply Design and Installation Practices and Procedures',3,'Install wiring systems and equipment in accordance with current relevant statutory and non-statutory regulations','3.3','Install the following in accordance with BS 7671, the installation specification and agreed planned programme of work: PVC Containment - Minimum of ONE a) PVC trunking; b) PVC conduit; AND Metallic Containment - Minimum of ONE c) Metallic conduit; d) Metallic trunking; AND Minimum of ONE from the following e) Cable tray; f) Cable basket; g) Ladder systems; h) Ducting; i) Modular wiring systems; j) Busbar systems or powertrack'),
('601/7345/2','NETP3-04A','Apply Design and Installation Practices and Procedures',3,'Install wiring systems and equipment in accordance with current relevant statutory and non-statutory regulations','3.4','Install the following types of electrical equipment and accessories, in accordance with BS 7671, the installation specification, manufacturers'' instructions and the programme of work: Cover five a) Isolators/switches; b) Socket-outlets; c) Distribution-boards/consumer control units; d) Overcurrent protective devices; e) Luminaires; f) Data socket-outlets/Wi-Fi router; g) Electric vehicle charging point; h) Other appropriate equipment (Such as: heating system components, control equipment, fire detection components, smart camera, smart lighting or heating control (N.B. An individual smart lamp is not sufficient))'),
('601/7345/2','NETP3-04A','Apply Design and Installation Practices and Procedures',3,'Install wiring systems and equipment in accordance with current relevant statutory and non-statutory regulations','3.5','Communicate with others professionally and appropriately to aid the effective installation of the wiring system/equipment'),
('601/7345/2','NETP3-04A','Apply Design and Installation Practices and Procedures',3,'Install wiring systems and equipment in accordance with current relevant statutory and non-statutory regulations','3.6','Dispose of waste materials in accordance with site procedures and statutory requirements'),
('601/7345/2','NETP3-04A','Apply Design and Installation Practices and Procedures',4,'Confirm the quality of the completed work','4.1','Ensure the installed wiring system/s and enclosure/s meet specified requirements, including that they: a) Are the correct type and fit for purpose; b) Are installed in accordance with BS 7671; c) Meet the installation specification/other relevant plans/instructions; d) Are installed in accordance with any relevant manufacturer instructions');
INSERT INTO qualification_requirements (qualification_code, unit_code, unit_title, lo_number, lo_text, ac_code, ac_text) VALUES
('601/7345/2','NETP3-05','Termination and Connection of Conductors',1,'Prepare to terminate and connect cables and conductors','1.1','Evaluate and apply appropriate procedures to include: a) selecting appropriate tools/equipment to enable termination and connection; b) adopting appropriate PPE; c) following a safe system of work (e.g. risk assessment, method statement, permit to work procedure)'),
('601/7345/2','NETP3-05','Termination and Connection of Conductors',1,'Prepare to terminate and connect cables and conductors','1.2','Assess and confirm it is safe to complete termination and connection in terms of: a) checking for presence of supply/carrying out safe isolation; b) mechanical soundness of the electrical equipment to be connected to; c) checking for unsafe situations'),
('601/7345/2','NETP3-05','Termination and Connection of Conductors',2,'Terminate and connect conductors and cables','2.1','Terminate and connect cables and conductors in accordance with manufacturers instructions, BS 7671, and any relevant drawing or specification: a) single core cable (singles); b) multicore insulated cable; c) PVC / PVC flat profile cable (twin and earth); d) MICC cable; e) fire performance (such as FP 200 etc.); f) SWA cable; g) GSWB galvanised steel wire braid; h) data cable'),
('601/7345/2','NETP3-05','Termination and Connection of Conductors',2,'Terminate and connect conductors and cables','2.2','Connect to electrical equipment in accordance with manufacturers instructions, BS 7671, and any relevant drawing or specification: a) isolators/switches; b) socket outlets; c) distribution-boards / consumer control units; d) luminaires; e) electric motors / motor control equipment; f) overcurrent protective devices; g) earthing terminals; h) control panels; i) data socket outlets or data connections; j) fire detection/alarm components; k) other appropriate equipment (such as: heating system components etc.)'),
('601/7345/2','NETP3-05','Termination and Connection of Conductors',2,'Terminate and connect conductors and cables','2.3','Terminate and connect conductors, using appropriate methods: a) screwing; b) crimping; c) soldering; d) non-screw compression; e) insulation displacement'),
('601/7345/2','NETP3-05','Termination and Connection of Conductors',2,'Terminate and connect conductors and cables','2.4','Ensure that terminations and connections are electrically and mechanically sound (e.g. by simple inspecting and testing terminations)'),
('601/7345/2','NETP3-05','Termination and Connection of Conductors',2,'Terminate and connect conductors and cables','2.5','Ensure cables have appropriate identification in accordance with BS 7671');
INSERT INTO qualification_requirements (qualification_code, unit_code, unit_title, lo_number, lo_text, ac_code, ac_text) VALUES
('601/7345/2','NETP3-06','Inspect, Test and Commission Electrical Systems',1,'Be able to confirm the safety of the system and equipment prior to completion of inspection, testing and commissioning in accordance with statutory and non-statutory regulations','1.1','Carry out safe isolation procedures in accordance with regulatory requirements for electrical installations'),
('601/7345/2','NETP3-06','Inspect, Test and Commission Electrical Systems',1,'Be able to confirm the safety of the system and equipment prior to completion of inspection, testing and commissioning in accordance with statutory and non-statutory regulations','1.2','Ensure the health and safety of themselves and others within the work location during inspection, testing and commissioning'),
('601/7345/2','NETP3-06','Inspect, Test and Commission Electrical Systems',1,'Be able to confirm the safety of the system and equipment prior to completion of inspection, testing and commissioning in accordance with statutory and non-statutory regulations','1.3','Check the safety of electrical systems prior to the commencement of inspection, testing and commissioning'),
('601/7345/2','NETP3-06','Inspect, Test and Commission Electrical Systems',2,'Be able to inspect electrical systems and equipment','2.1','Assess whether the safe system of work is appropriate to the work activity'),
('601/7345/2','NETP3-06','Inspect, Test and Commission Electrical Systems',2,'Be able to inspect electrical systems and equipment','2.2','Carry out a visual inspection in accordance with the requirements of the installation specification, BS 7671 and IET Guidance Note 3'),
('601/7345/2','NETP3-06','Inspect, Test and Commission Electrical Systems',2,'Be able to inspect electrical systems and equipment','2.3','Complete a schedule of inspections in accordance with BS 7671 and IET Guidance Note 3 making technical decisions'),
('601/7345/2','NETP3-06','Inspect, Test and Commission Electrical Systems',3,'Be able to test and commission electrical systems and equipment','3.1','Select the correct test instruments and their accessories for tests'),
('601/7345/2','NETP3-06','Inspect, Test and Commission Electrical Systems',3,'Be able to test and commission electrical systems and equipment','3.2','Carry out tests in accordance with the installation specification and BS 7671 and manufacturers'' instructions: a) Continuity; b) Insulation resistance; c) Polarity; d) Earth fault loop impedance/earth electrode resistance; e) Prospective fault current; f) RCD operation; g) Functional testing'),
('601/7345/2','NETP3-06','Inspect, Test and Commission Electrical Systems',3,'Be able to test and commission electrical systems and equipment','3.3','Analyse and verify test results reporting all findings to relevant persons, as appropriate: a) Representatives of other services/colleagues; b) Customers/clients'),
('601/7345/2','NETP3-06','Inspect, Test and Commission Electrical Systems',3,'Be able to test and commission electrical systems and equipment','3.4','Complete in accordance with BS 7671 and IET Guidance Note 3: a) An Electrical Installation Certificate, complete with related schedules; b) A Minor Electrical Installation Works Certificate'),
('601/7345/2','NETP3-06','Inspect, Test and Commission Electrical Systems',3,'Be able to test and commission electrical systems and equipment','3.5','Complete the handover of electrical systems and equipment to relevant persons including the provision of accurate and complete documentation regarding the completed inspection, testing, commissioning and customer satisfaction'),
('601/7345/2','NETP3-06','Inspect, Test and Commission Electrical Systems',3,'Be able to test and commission electrical systems and equipment','3.6','Demonstrate to the customer/client that the operation of the circuits, equipment and components are in accordance with the installation specification and customer/client requirements');
INSERT INTO qualification_requirements (qualification_code, unit_code, unit_title, lo_number, lo_text, ac_code, ac_text) VALUES
('601/7345/2','NETP3-07','Apply Fault Diagnosis and Rectification',1,'Prepare to carry out fault diagnosis','1.1','Check it is safe to carry out fault diagnosis'),
('601/7345/2','NETP3-07','Apply Fault Diagnosis and Rectification',1,'Prepare to carry out fault diagnosis','1.2','Inform the relevant personnel of the fault diagnosis work (such as personnel on the premises, users of electrical equipment)'),
('601/7345/2','NETP3-07','Apply Fault Diagnosis and Rectification',1,'Prepare to carry out fault diagnosis','1.3','Carry out the safe isolation procedure'),
('601/7345/2','NETP3-07','Apply Fault Diagnosis and Rectification',1,'Prepare to carry out fault diagnosis','1.4','Evaluate and apply appropriate methods to ensure the safety of themselves and others when diagnosing and correcting electrical faults'),
('601/7345/2','NETP3-07','Apply Fault Diagnosis and Rectification',2,'Carry out fault diagnosis','2.1','Communicate effectively with relevant personnel (e.g. customer, premises manager) to ascertain the nature of the fault'),
('601/7345/2','NETP3-07','Apply Fault Diagnosis and Rectification',2,'Carry out fault diagnosis','2.2','Select and interpret appropriate documents (e.g. layout drawings, schematic diagrams etc) which relate to the electrical systems and equipment being worked upon'),
('601/7345/2','NETP3-07','Apply Fault Diagnosis and Rectification',2,'Carry out fault diagnosis','2.3','Assess and communicate potential disruption that may be a consequence of fault diagnosis and correction work to relevant people (such as other workers/colleagues Customers/clients)'),
('601/7345/2','NETP3-07','Apply Fault Diagnosis and Rectification',2,'Carry out fault diagnosis','2.4','Carry out relevant inspections of electrical equipment analysing findings'),
('601/7345/2','NETP3-07','Apply Fault Diagnosis and Rectification',2,'Carry out fault diagnosis','2.5','Confirm test instruments are fit for purpose, functioning correctly and are correctly calibrated'),
('601/7345/2','NETP3-07','Apply Fault Diagnosis and Rectification',2,'Carry out fault diagnosis','2.6','Perform suitable diagnostic tests, based on engineering decision, to identify electrical faults: a) loss of supply; b) overload; c) short-circuit; d) earth fault; e) incorrect phase rotation; f) high resistance joints/loose terminations; g) component, accessory or equipment faults; h) open circuit; i) signal faults'),
('601/7345/2','NETP3-07','Apply Fault Diagnosis and Rectification',2,'Carry out fault diagnosis','2.7','Use appropriate methods for locating faults including: a) using a logical approach; b) using safe working practices; c) interpretation of test readings'),
('601/7345/2','NETP3-07','Apply Fault Diagnosis and Rectification',2,'Carry out fault diagnosis','2.8','Use appropriate instruments correctly to carry out fault diagnosis: a) voltage indicator; b) low resistance ohm meter; c) insulation resistance tester; d) EFLI and PFC tester; e) RCD tester; f) ammeter; g) phase rotation tester; h) other appropriate instrument'),
('601/7345/2','NETP3-07','Apply Fault Diagnosis and Rectification',3,'Carry out fault rectification','3.1','Assess the appropriate repairs, removals and replacements and their implications with relevant people: a) other workers/colleagues; b) customers/clients'),
('601/7345/2','NETP3-07','Apply Fault Diagnosis and Rectification',3,'Carry out fault rectification','3.2','Perform fault correction procedures correctly and safely using appropriate tools, equipment and material'),
('601/7345/2','NETP3-07','Apply Fault Diagnosis and Rectification',3,'Carry out fault rectification','3.3','Assess and verify that replacement components and associated equipment maintain: a) ease of access to enable future maintenance; b) compliance with relevant regulations; c) compliance with manufacturer’s instructions/organisational procedures'),
('601/7345/2','NETP3-07','Apply Fault Diagnosis and Rectification',3,'Carry out fault rectification','3.4','Apply appropriate procedures to ensure electrical equipment and components are left safe, in accordance with industry regulations, if the fault cannot be corrected immediately based on technical assessment.'),
('601/7345/2','NETP3-07','Apply Fault Diagnosis and Rectification',3,'Carry out fault rectification','3.5','Establish and perform an appropriate inspection and testing procedure to confirm that circuits/equipment/components are functioning correctly after completion of fault correction work'),
('601/7345/2','NETP3-07','Apply Fault Diagnosis and Rectification',3,'Carry out fault rectification','3.6','Record test results and other appropriate information regarding the fault correction work clearly and accurately and report it to relevant people: a) other workers/colleagues; b) customers/clients; c) representatives of other services');
INSERT INTO qualification_requirement_mappings (qualification_code, requirement_code, is_primary)
