-- =====================================================================
-- EAL Level 3 Electrotechnical Qualification — 601/7345/2 (Issue 8, (c) EAL 2025)
-- Seeds the RAG "brain" (qualification_requirements) so College Hub +
-- Apprentice Hub support EAL learners identically to City & Guilds.
--
-- Source: authoritative (c) EAL 2025 unit PDFs (NETK3 Delivery Units + NETP3
-- Performance Units) + Qualification Specification Issue 8 (601/7345/2).
-- Every LO/AC transcribed verbatim from source then adversarially verified
-- against the source text (no invention; Delivery-Advice column excluded).
--
-- Combined qualification: mandatory knowledge (NETK3) + performance (NETP3)
-- units under ONE qualification_code.
--
-- AFTER applying: invoke edge function `embed-qualification-requirements`
-- (text-embedding-3-small, 1536-dim) to populate the `embedding` column;
-- rows are NULL-embedded on INSERT by trigger and are invisible to
-- match_qualification_acs until embedded.
-- =====================================================================

BEGIN;

-- 1) Qualification row (id is uuid DEFAULT gen_random_uuid(); no unique on code, so guard by NOT EXISTS)
SELECT 'EAL','Level 3','Level 3 Electrotechnical Qualification','601/7345/2',
  'EAL Level 3 Electrotechnical Qualification. 745 GLH, TQT 866h. Combined knowledge (NETK3) and on-site performance (NETP3) units; occupational competence also requires the AM2S. Mandatory units plus one optional pathway performance unit.',
  true
WHERE NOT EXISTS (SELECT 1 FROM qualifications WHERE code='601/7345/2');

-- 2) Remove the old unsourced EAL-NETP3 backbone (verified zero student_ac_coverage).
--    NOTE: EAL-NETP3 was the shared requirement_code for 9 EAL quals via
--    qualification_requirement_mappings; section 5 repoints them all to 601/7345/2.
DELETE FROM qualification_requirements WHERE qualification_code = 'EAL-NETP3';
-- 3) Idempotent re-seed of this code
DELETE FROM qualification_requirements WHERE qualification_code = '601/7345/2';

-- 4) Insert unit LO/AC rows


-- NETK3-01  Understand Health, Safety and Environmental Considerations (65 GLH) · Ofqual H/507/7334 · knowledge · verify=pass · 4 LOs / 26 ACs

-- NETK3-03  Understand How to Plan and Oversee Electrical Work Activities (40 GLH) · Ofqual K/507/7335 · knowledge · verify=pass · 3 LOs / 17 ACs

-- NETK3-04  Understand Design and Installation Practices and Procedures (170 GLH) · Ofqual M/507/7336 · knowledge · verify=corrected · 8 LOs / 45 ACs

-- NETK3-05  Understand Terminations and Connections of Conductors (93 GLH) · Ofqual T/507/7337 · knowledge · verify=pass · 2 LOs / 7 ACs

-- NETK3-06A  Inspection, Testing and Commissioning (80 GLH) · Ofqual A/650/7479 · knowledge · verify=pass · 11 LOs / 59 ACs

-- NETK3-07  Understand Fault Diagnosis and Rectification (32 GLH) · Ofqual F/507/7339 · knowledge · verify=pass · 6 LOs / 21 ACs

-- NETK3-08  Electrical Scientific Principles and Technologies (115 GLH) · Ofqual T/507/7340 · knowledge · verify=pass · 12 LOs / 47 ACs

-- NETP3-01  Apply Health, Safety and Environmental Considerations (10 GLH) · Ofqual F/507/7342 · performance · verify=pass · 4 LOs / 14 ACs

-- NETP3-03  Organise and Oversee the Electrical Work Environment (12 GLH) · Ofqual J/507/7343 · performance · verify=pass · 6 LOs / 18 ACs

-- NETP3-04A  Apply Design and Installation Practices and Procedures (20 GLH) · Ofqual T/650/7477 · performance (optional: Installation pathway) · verify=pass · 4 LOs / 13 ACs

-- NETP3-05  Termination and Connection of Conductors (12 GLH) · Ofqual Y/650/7478 (current eq. NETP3-05A) · performance · verify=pass · 2 LOs / 7 ACs

-- NETP3-06  Inspect, Test and Commission Electrical Systems (16 GLH) · Ofqual R/507/7345 · performance · verify=pass · 3 LOs / 12 ACs

-- NETP3-07  Apply Fault Diagnosis and Rectification (10 GLH) · Ofqual Y/507/7346 · performance · verify=pass · 3 LOs / 18 ACs

-- 5) Repoint every EAL qualification that referenced the retired EAL-NETP3
--    backbone onto the new authoritative 601/7345/2 requirement set.
DELETE FROM qualification_requirement_mappings WHERE requirement_code='EAL-NETP3';
SELECT q, '601/7345/2', true
FROM (VALUES
  ('603/3929/9'),  -- EAL L3 Electrotechnical (Installation) NVQ
  ('603/3928/7'),  -- EAL L3 Electrotechnical (Maintenance) NVQ
  ('603/3895/8'),  -- Installation & Maintenance Electrician Apprenticeship (ST0152)
  ('603/0149/3'),  -- BSE Craftsperson (Electrical)
  ('603/5806/9'),  -- BSE Installer (Electrical) Apprenticeship
  ('603/4027/6'),  -- Electrotechnical Experienced Worker
  ('600/4337/4'),  -- Electrotechnical Occupational Competence (AM2 Gateway)
  ('603/5933/7'),  -- EAL T Level BSE - Electrical Installation
  ('EAL-NETP3')    -- retired code, keep resolvable
) AS v(q)
WHERE NOT EXISTS (
  SELECT 1 FROM qualification_requirement_mappings m
  WHERE m.qualification_code=v.q AND m.requirement_code='601/7345/2'
);

COMMIT;

-- Total: 13 units, 304 ACs
-- 6) AFTER COMMIT: backfill embeddings (rows are NULL-embedded on INSERT by the
--    qualification_requirements_clear_embedding trigger; invisible to
--    match_qualification_acs until embedded). text-embedding-3-small, 1536-dim:
--      POST /functions/v1/embed-qualification-requirements  (service-role JWT or X-Admin-Key)
--    or via SQL using pg_net + vault:
--      SELECT net.http_post(
--        url := '<project>/functions/v1/embed-qualification-requirements',
--        headers := jsonb_build_object('Content-Type','application/json',
--          'Authorization','Bearer ' || (SELECT decrypted_secret FROM vault.decrypted_secrets WHERE name='service_role_key')),
--        body := '{}'::jsonb);
